  (E'DF-2026-020'::text, E'DF'::text, E'Misterimiz tarafindan iletilen ve ekte yer alan gérseller incelendiginde , KADEMEtarafindan sevk edilen son 2 | adet Ural araci Gzerinde asagida belirtilen sevkiyat kaynakli uygunsuzluklar tespit edilmistir : | Gévde saclari ve sasi tizeri boyali yiizeylerde carpma , siirtme ve lokal boya hasarlar! , | KADEMEisim plakasinin (name plate) hasar gérdiigii / deforme oldugu , | Arag izerindeki ikaz lambalarindan birinin kirik oldugu (misteri , detay igin Engr. Ahmed ile iletisime gecilmesini'::text, E'Depo operasyonlarında standardı olmayan uygulamalar ve tekrarlayan hatalar yaşanmaktadır.'::text, E'Personel işlemleri kendi inisiyatifine göre yapmakta, standart bir yol izlememektedir.'::text, E'Hangi işlemin nasıl yapılacağına dair güncel ve erişilebilir talimat mevcut değildir.'::text, E'Mevcut prosedürler son değişiklikleri yansıtmayacak kadar eskidir veya hiç yazılmamıştır.'::text, E'Prosedür güncelleme sorumluluğu sahiplenilmemekte; periyodik gözden geçirme yapılmamaktadır.'::text, E'Depo süreçleri için bir dokümantasyon yönetim planı (revizyon periyodu, onay mekanizması) oluşturulmamıştır.'::text, E'Misterimiz tarafindan iletilen ve ekte yer alan gérseller incelendiginde , KADEMEtarafindan sevk edilen son 2 | adet Ura'::text, E'Depo'::text, E'20.02.2026'::text, E'‘Sinan Acar'::text, E'Depo yönetim prosedürü eksik veya güncel değil'::text, E'Depo rutin sayımı, giriş/çıkış takibi veya saha bildirimi ile tespit edilmiştir.'::text, E'1. İlgili uygunsuzluk için yazılı prosedür/talimat oluşturulmalı veya güncellenmeli; depo personeline iletilmelidir.\n2. Haftalık depo kontrol turu uygulanmalı; bulgular kayıt altına alınmalıdır.\n3. Depo personeline yönlendirici eğitim verilmeli ve eğitim kaydı tutulmalıdır.\n4. 5S uygulaması kapsamında depo düzenlemesi yapılmalıdır.'::text)
  ) AS t(nc_number, typ, problem_def, symptom, why1, why2, why3, why4, why5, ne, nerede, ne_zaman, kim, neden, nasil, actions_text)
)
UPDATE non_conformities n
SET
  five_n1k_analysis = jsonb_build_object(
    'ne', to_jsonb(x.ne),
    'nerede', to_jsonb(x.nerede),
    'neZaman', to_jsonb(x.ne_zaman),
    'kim', to_jsonb(x.kim),
    'neden', to_jsonb(x.neden),
    'nasil', to_jsonb(x.nasil)
  ),
  five_why_analysis = jsonb_build_object(
    'problem', to_jsonb(x.problem_def),
    'why1', to_jsonb(x.why1),
    'why2', to_jsonb(x.why2),
    'why3', to_jsonb(x.why3),
    'why4', to_jsonb(x.why4),
    'why5', to_jsonb(x.why5),
    'rootCause', to_jsonb(x.why5),
    'immediateAction', to_jsonb(x.neden),
    'preventiveAction', to_jsonb(x.actions_text)
  ),
  eight_d_steps = CASE
    WHEN n.type = '8D' THEN
      jsonb_set(
        jsonb_set(
          COALESCE(n.eight_d_steps, '{}'::jsonb),
          '{D4,description}',
          to_jsonb(
            ('5 Neden (özet)'::text || E'\n\n' ||
             '1. ' || x.why1 || E'\n' ||
             '2. ' || x.why2 || E'\n' ||
             '3. ' || x.why3 || E'\n' ||
             '4. ' || x.why4 || E'\n' ||
             '5 (Kök): ' || x.why5)::text
          ),
          true
        ),
        '{D5,description}',
        to_jsonb(('Önerilen düzeltici faaliyetler'::text || E'\n\n' || x.actions_text)::text),
        true
      )
    ELSE n.eight_d_steps
  END,
  updated_at = now()
FROM x
WHERE n.nc_number = x.nc_number AND n.type = x.typ;
